#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline bool Get(){char c;do c=getchar();while(c!='0'&&c!='1');return c=='1';}
const int N=410,INF=0x3f3f3f3f;
int fa[N],n,m,sz[N],dp[N][N];bool ty[N];int a[2][N];
inline int fnd(int x){return fa[x]==x?x:fa[x]=fnd(fa[x]);}
inline int F(int i,int j){return (i-1)*m+j;}
int main()
{
	n=read();m=read();rep(1,n*m,i)fa[i]=i,sz[i]=1;
	rep(1,n+1,i)rep(1,m,j)if(!Get())
	{
		if(i==1||i==n+1)ty[fnd(F(i==1?1:n,j))]=true;
		else
		{
			int x=fnd(F(i-1,j)),y=fnd(F(i,j));
			if(x!=y)fa[x]=y,ty[y]|=ty[x],sz[y]+=sz[x];
		}
	}
	rep(1,n,i)rep(1,m+1,j)if(!Get())
	{
		if(j==1||j==m+1)ty[fnd(F(i,j==1?1:m))]=true;
		else
		{
			int x=fnd(F(i,j-1)),y=fnd(F(i,j));
			if(x!=y)fa[x]=y,ty[y]|=ty[x],sz[y]+=sz[x];
		}
	}
//	rep(0,1,i)a[i].push_back(INF);
	int M[2]={0,0};
	rep(1,n,i)rep(1,m,j)if(fnd(F(i,j))==F(i,j))
	{
		bool q=ty[F(i,j)]^1;
		if(q){if(sz[F(i,j)]!=1)a[1][++M[1]]=sz[F(i,j)];}
		else a[0][++M[0]]=sz[F(i,j)];
	}
	rep(0,1,i)sort(a[i]+1,a[i]+M[i]+1,[&](const int &x,const int &y){return x>y;});
//	memset(dp,~0x3f,sizeof(dp));
	rep(0,M[0],i)
	{
		rep(0,M[1],j)
		{
			if(!i&&!j){dp[i][j]=0;continue;}
			else dp[i][j]=~INF;
			if(i)
			{
				if(a[0][i]>2)
				{
					dp[i][j]=-max(a[0][i]+dp[i-1][j],a[0][i]-4-dp[i-1][j]);
				}
				else
				{
					dp[i][j]=-a[0][i]-dp[i-1][j];
				}
			}
			if(j)
			{
				dp[i][j]=max(dp[i][j],-max(a[1][j]+dp[i][j-1],a[1][j]-8-dp[i][j-1]));
			}
		}
	}
	printf("%d\n",dp[M[0]][M[1]]);
	
}
